const defaultTargetAgentId = "task_performing_agent";
const actingAgentId = "905cdf83-5970-4598-8642-dea17852cc99";
const boundDispatchOperationTypes: string[] = ["display"];
const operationTypes = new Set([
  "display",
  "agent_call",
  "tool_call",
]);

const collapseWhitespace = (value: string): string =>
  value.replace(/\s+/g, " ").trim();
const asRecord = (value: unknown): Record<string, unknown> | null =>
  value && typeof value === "object" && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : null;
const asText = (value: unknown): string =>
  typeof value === "string" ? collapseWhitespace(value) : "";
const parseJsonLike = (value: unknown): unknown => {
  if (typeof value !== "string") return value;
  const trimmed = value.trim();
  if (!trimmed) return value;
  try {
    return JSON.parse(trimmed);
  } catch {
    return value;
  }
};
const normalizeOperationType = (value: unknown): string => {
  const normalized = asText(value).toLowerCase().replace(/[\s-]+/g, "_");
  if (normalized === "call_agent" || normalized === "agent") return "agent_call";
  if (normalized === "call_tool" || normalized === "tool") return "tool_call";
  if (normalized === "message" || normalized === "reply") return "display";
  return operationTypes.has(normalized) ? normalized : "display";
};
const normalizePayload = (value: unknown): unknown => {
  if (value === undefined) return null;
  if (typeof value === "string") return collapseWhitespace(value);
  return value;
};

const normalizeOperation = (rawValue: unknown, forcedType = "") => {
  const parsed = parseJsonLike(rawValue);
  const record = asRecord(parsed);
  if (!record) {
    const payload = normalizePayload(parsed);
    if (payload === null || payload === "") return null;
    return { type: forcedType || "display", payload };
  }
  const rawPayload =
    record.payload ??
    record.message ??
    record.content ??
    record.assistantMessage ??
    record.observation ??
    (typeof record.action === "string" ? record.action : undefined);
  const payload = normalizePayload(rawPayload);
  const toolName = asText(record.toolName ?? record.tool_name);
  const metadata = asRecord(record.metadata);
  return {
    type:
      forcedType ||
      normalizeOperationType(record.type ?? record.actionType ?? record.kind),
    payload,
    ...(toolName ? { toolName } : {}),
    ...(record.input !== undefined ? { input: record.input } : {}),
    ...(metadata ? { metadata } : {}),
  };
};

const normalizeAction = (rawValue: unknown) => {
  const parsed = parseJsonLike(rawValue);
  let record = asRecord(parsed);
  if (record) {
    const nestedLatestAction = parseJsonLike(record.agent_latest_action);
    const nestedAction = parseJsonLike(record.action);
    record = asRecord(nestedLatestAction) ?? asRecord(nestedAction) ?? record;
  }

  if (!record) {
    if (!defaultTargetAgentId) return null;
    const firstOperation = normalizeOperation(
      parsed,
      boundDispatchOperationTypes[0] ?? ""
    );
    if (!firstOperation) return null;
    const operations =
      boundDispatchOperationTypes.length > 0
        ? boundDispatchOperationTypes.map((type, index) =>
            index === 0 ? firstOperation : { type, payload: null }
          )
        : [firstOperation];
    return {
      targetAgentId: defaultTargetAgentId,
      operations,
    };
  }

  const requestedTargetAgentId = asText(
      record.targetAgentId ??
        record.target_agent_id ??
        record.recipientAgentId ??
        record.recipient_agent_id
    );
  const targetAgentId =
    !requestedTargetAgentId || requestedTargetAgentId === actingAgentId
      ? defaultTargetAgentId
      : requestedTargetAgentId;
  if (!targetAgentId || targetAgentId === actingAgentId) return null;
  const rawOperations = Array.isArray(record.operations)
    ? record.operations
    : Array.isArray(record.actions)
      ? record.actions
      : Array.isArray(record.dispatches)
        ? record.dispatches
        : [record];
  const operations =
    boundDispatchOperationTypes.length > 0
      ? boundDispatchOperationTypes.map((type, index) =>
          normalizeOperation(rawOperations[index] ?? {}, type) ?? {
            type,
            payload: null,
          }
        )
      : rawOperations
          .map((operation) => normalizeOperation(operation))
          .filter((operation): operation is Record<string, unknown> => operation !== null);
  if (operations.length === 0) return null;
  const rawMetadata = asRecord(record.metadata);
  const reward = record.target_reward ?? record.reward_for_target ?? record.reward;
  const metadata = {
    ...(rawMetadata ?? {}),
    ...(reward !== undefined ? { reward } : {}),
  };

  return {
    targetAgentId,
    operations,
    ...(Object.keys(metadata).length > 0 ? { metadata } : {}),
  };
};

const readPolicyOutput = (): unknown => {
  const statePayload = parseJsonLike(ctx.state.selected_task);
  const statePayloadRecord = asRecord(statePayload);
  if (
    statePayload === null ||
    statePayload === undefined ||
    statePayload === "" ||
    (statePayloadRecord && Object.keys(statePayloadRecord).length === 0)
  ) {
    throw new Error("The state canvas did not persist a value in selected_task.");
  }
  return {
    targetAgentId: defaultTargetAgentId,
    operations: [{
      type: boundDispatchOperationTypes[0] ?? "display",
      payload: statePayload,
    }],
    metadata: {"reward":0},
  };
};
const committedAction = normalizeAction(readPolicyOutput());
if (!committedAction) return {};

const fieldNames = Object.keys(ctx.state);
const findField = (canonicalName: string): string | null =>
  fieldNames.find((name) => name.trim().toLowerCase() === canonicalName) ?? null;
const memoryFieldName = findField("new_events") ??
  findField("new_conversations");
const latestActionFieldName = findField("agent_latest_action");
const latestObservationFieldName = findField("agent_latest_observation");
const latestRewardFieldName = findField("agent_latest_reward");
const fieldType = (fieldName: string | null): string =>
  fieldName
    ? ctx.stateSchema.find((field) => field.fieldName === fieldName)?.type ?? "string"
    : "string";
const latestObservation = latestObservationFieldName
  ? ctx.state[latestObservationFieldName] ?? null
  : null;
const latestReward = latestRewardFieldName
  ? ctx.state[latestRewardFieldName] ?? null
  : null;

const parseEvents = (value: unknown): Array<Record<string, unknown>> => {
  const parsed = parseJsonLike(value);
  return Array.isArray(parsed)
    ? parsed
        .filter(
          (entry): entry is Record<string, unknown> => asRecord(entry) !== null
        )
        .map((entry) => ({ ...entry }))
    : [];
};
const events = memoryFieldName ? parseEvents(ctx.state[memoryFieldName]) : [];
const latestEvent = events[events.length - 1];
if (latestEvent && (latestEvent.action === null || latestEvent.action === undefined || latestEvent.action === "")) {
  latestEvent.action = committedAction;
  if (latestEvent.observation === null || latestEvent.observation === undefined || latestEvent.observation === "") {
    latestEvent.observation = latestObservation;
  }
  if (latestEvent.reward === null || latestEvent.reward === undefined || latestEvent.reward === "") {
    latestEvent.reward = latestReward;
  }
} else {
  events.push({
    action: committedAction,
    observation: latestObservation,
    reward: latestReward,
  });
}

const setState: Record<string, unknown> = {};
if (latestActionFieldName) {
  setState[latestActionFieldName] =
    fieldType(latestActionFieldName) === "json"
      ? committedAction
      : JSON.stringify(committedAction);
}
if (memoryFieldName) {
  setState[memoryFieldName] =
    fieldType(memoryFieldName) === "json" ? events : JSON.stringify(events);
}

const operationLocals = committedAction.operations.reduce(
  (locals: Record<string, unknown>, operation: Record<string, unknown>, index: number) => {
    locals[`committed_action_operation_${index}`] = operation;
    locals[`committed_action_operation_${index}_payload`] = operation.payload;
    locals[`committed_action_operation_${index}_input`] = operation.input ?? null;
    locals[`committed_action_operation_${index}_dispatch_input`] =
      operation.input ?? operation.payload ?? null;
    return locals;
  },
  {}
);
const firstPayload = committedAction.operations[0]?.payload ?? null;

return {
  setState,
  setLocals: {
    committed_action: committedAction,
    committed_action_payload: firstPayload,
    carried_output: firstPayload,
    ...operationLocals,
  },
};
